import React, { useState, useRef } from 'react';
import { analyzeImage, ApiError, PredictionResponse } from '../services/api';
import './UploadPage.css';

interface AnalysisResult extends PredictionResponse {
  duration?: number;
  stage?: string;
}

const UploadPage: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showBrainOnlyPopup, setShowBrainOnlyPopup] = useState(false);
  const [analysisStep, setAnalysisStep] = useState<'idle' | 'uploading' | 'analyzing'>('idle');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // ✅ FILE UPLOAD (NO STRICT VALIDATION)
  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0] || null;
    if (!file) return;

    // Size check
    if (file.size > 10 * 1024 * 1024) {
      setError('File size exceeds 10MB limit');
      return;
    }

    // Format check
    const allowedExtensions = ['jpg', 'jpeg', 'png', 'jfif', 'bmp', 'webp', 'tiff', 'tif'];
    const fileExtension = file.name.split('.').pop()?.toLowerCase();

    if (!fileExtension || !allowedExtensions.includes(fileExtension)) {
      setError('Invalid file type.');
      return;
    }

    // ✅ ACCEPT IMAGE
    setSelectedFile(file);
    setPreviewUrl(URL.createObjectURL(file));
    setError(null);
    setResult(null);
  };

  // ✅ ANALYSIS WITH MODEL VALIDATION
  const handleAnalyzeImage = async () => {
    if (!selectedFile) {
      setError('Please select an MRI image.');
      return;
    }

    setLoading(true);
    setError(null);
    setResult(null);

    try {
      setAnalysisStep('uploading');

      const response = await analyzeImage(selectedFile);

      // ❌ Reject non-brain images
      if (!response || !response.prediction) {
        setShowBrainOnlyPopup(true);
        setSelectedFile(null);
        setPreviewUrl(null);
        setError("Only brain MRI images are allowed.");
        return;
      }

      setAnalysisStep('analyzing');

      setResult(response);
      setAnalysisStep('idle');

    } catch (err) {
      const apiError = err as ApiError;
      setError(apiError.error || 'Analysis failed');
    } finally {
      setLoading(false);
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleRemoveFile = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setError(null);
    setResult(null);

    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="upload-page">

      {/* Popup */}
      {showBrainOnlyPopup && (
        <div className="popup-overlay">
          <div className="popup-content">
            <h3>Upload Brain MRI Only</h3>
            <p>Please upload a valid brain MRI image.</p>
            <button onClick={() => setShowBrainOnlyPopup(false)}>OK</button>
          </div>
        </div>
      )}

      <div className="upload-container">
        <h1>Brain MRI Analysis</h1>

        <input
          ref={fileInputRef}
          type="file"
          accept=".jpg,.jpeg,.png,.jfif,.bmp,.webp,.tiff,.tif"
          onChange={handleFileChange}
          style={{ display: 'none' }}
        />

        {!selectedFile ? (
          <div className="upload-area" onClick={handleUploadClick}>
            <p>Click to upload MRI image</p>
          </div>
        ) : (
          <div>
            <p>{selectedFile.name}</p>
            <img src={previewUrl!} className="preview-image" alt="preview" />
            <button onClick={handleRemoveFile}>Remove</button>
          </div>
        )}

        {error && <p className="error">{error}</p>}

        {selectedFile && !loading && !result && (
          <button onClick={handleAnalyzeImage}>
            Analyze Image
          </button>
        )}

        {loading && <p>Analyzing...</p>}

        {result && (
          <div>
            <h3>{result.prediction === 'tumor' ? 'Tumor Detected' : 'No Tumor Found'}</h3>
            <p>Confidence: {result.confidence}%</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default UploadPage;
```;

